from rest_framework import serializers
from .models import CustomUser, UserProfile
from rest_framework.validators import UniqueValidator
from django.contrib.auth.password_validation import validate_password
from rest_framework.exceptions import ValidationError
from django.db import transaction
from django.contrib.auth import get_user_model
from drf_spectacular.utils import extend_schema_field, extend_schema_serializer
from tagging.models import TaggedItem

User = get_user_model()

@extend_schema_serializer(
    description="Serializer for UserProfile, containing personal details and tagging information.",
    examples=[
        {
            "first_name": "John",
            "last_name": "Doe",
            "gender": "male",
            "date_of_birth": "1990-01-01",
            "profile_picture": "http://example.com/media/profile_pictures/user123.jpg",
            "bio": "Software developer with 10 years of experience.",
            "phone": "+123456789",
            "town": "New York",
            "country": "USA",
            "relationship_status": "single",
            "tags": [
                {"tagged_user_id": "uuid", "tagged_by": "uuid", "timestamp": "2024-11-05T12:00:00Z"}
            ],
            "tagged_user_ids": ["uuid1", "uuid2"]
        }
    ]
)
class UserProfileSerializer(serializers.ModelSerializer):
    tags = serializers.SerializerMethodField()
    tagged_user_ids = serializers.ListField(
        child=serializers.UUIDField(format='hex_verbose'),
        write_only=True,
        required=False,
        help_text="List of user UUIDs to tag in the user profile."
    )

    class Meta:
        model = UserProfile
        fields = [
            'first_name', 'last_name', 'gender', 'date_of_birth',
            'profile_picture', 'bio', 'phone', 'town', 'country',
            'relationship_status', 'tags', 'tagged_user_ids'
        ]
        read_only_fields = ['tags']

    @extend_schema_field(serializers.ListField)  # Modify accordingly for schema representation
    def get_tags(self, instance) -> list:
        # Move the import here to avoid circular dependencies.
        from tagging.serializers import TaggedItemSerializer
        return TaggedItemSerializer(instance.tags.all(), many=True).data

    def update(self, instance, validated_data):
        tagged_user_ids = validated_data.pop('tagged_user_ids', None)
        profile = super().update(instance, validated_data)
        if tagged_user_ids is not None:
            instance.tags.all().delete()
            self.create_tagged_items(profile, tagged_user_ids)
        return profile

    def create_tagged_items(self, profile, tagged_user_ids):
        for user_id in tagged_user_ids:
            TaggedItem.objects.create(
                content_object=profile,
                tagged_user_id=user_id,
                tagged_by=self.context['request'].user
            )


@extend_schema_serializer(
    description="Serializer representing a user, including profile details and password management.",
    examples=[
        {
            "id": "123e4567-e89b-12d3-a456-426614174000",
            "email": "john.doe@example.com",
            "username": "johndoe",
            "password": "secure_password_123",
            "password2": "secure_password_123",
            "profile": {
                "first_name": "John",
                "last_name": "Doe",
                "gender": "male",
                "date_of_birth": "1990-01-01",
                "bio": "Software developer.",
                "phone": "+123456789",
                "town": "New York",
                "country": "USA",
                "relationship_status": "single",
                "tags": []
            }
        }
    ]
)
class CustomUserSerializer(serializers.ModelSerializer):
    profile = UserProfileSerializer(required=False)
    password = serializers.CharField(
        write_only=True,
        required=False,
        validators=[validate_password],
        style={'input_type': 'password'}
    )
    password2 = serializers.CharField(
        write_only=True,
        required=False,
        style={'input_type': 'password'},
        label="Confirm Password"
    )

    class Meta:
        model = CustomUser
        fields = [
            'id', 'email', 'username', 'password', 'password2', 'profile'
        ]
        extra_kwargs = {
            'email': {
                'validators': [UniqueValidator(queryset=CustomUser.objects.all())]
            },
            'username': {
                'validators': [UniqueValidator(queryset=CustomUser.objects.all())]
            },
        }

    def validate(self, data):
        """
        Ensure that both passwords match.
        """
        password = data.get('password')
        password2 = data.get('password2')

        if password or password2:
            if password != password2:
                raise ValidationError({"non_field_errors": ["Passwords do not match."]})
        return data

    def create(self, validated_data):
        """
        Create a new user instance after removing password2.
        """
        profile_data = validated_data.pop('profile', {})
        with transaction.atomic():
            user = CustomUser.objects.create(
                email=validated_data['email'],
                username=validated_data['username']
            )
            if 'password' in validated_data:
                user.set_password(validated_data['password'])
            user.save()

            if profile_data:
                # Retrieve the existing profile created by signals
                profile = user.profile
                profile_serializer = UserProfileSerializer(
                    profile,
                    data=profile_data,
                    partial=True,
                    context={'request': self.context.get('request')}
                )
                profile_serializer.is_valid(raise_exception=True)
                profile_serializer.save()

        return user

    def update(self, instance, validated_data):
        """
        Update user instance and associated profile.
        """
        profile_data = validated_data.pop('profile', {})
        instance.email = validated_data.get('email', instance.email)
        instance.username = validated_data.get('username', instance.username)
        if 'password' in validated_data:
            instance.set_password(validated_data['password'])
        instance.save()

        if profile_data:
            profile_serializer = UserProfileSerializer(
                instance.profile,
                data=profile_data,
                partial=True,
                context={'request': self.context.get('request')}
            )
            profile_serializer.is_valid(raise_exception=True)
            profile_serializer.save()

        return instance

    def get_serializer_context(self):
        """
        Ensure the request is passed in the context for nested serializers.
        """
        context = super().get_serializer_context()
        context.update({'request': self.context.get('request')})
        return context
